definition.script:
pipeline {
    agent none
    stages {
        stage('Back-end') {
            agent {
                docker { image 'maven:3-eclipse-temurin-25-noble' }
            }
            steps {
                sh 'mvn --version'
            }
        }
        stage('Front-end') {
            agent {
                docker { image 'node:24-alpine' }
            }
            steps {
                sh 'node --version'
            }
        }
    }
}
